import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { SeedService } from '../../data/seed.service';

interface MonthBar {
  month: string;
  value: number;
  pct: number;
}

interface AccountBar {
  name: string;
  value: number;
  pct: number;
}

@Component({
  selector: 'app-revenue',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './revenue.component.html',
  styleUrl: './revenue.component.css',
})
export class RevenueComponent {
  readonly tabs = ['revenue', 'commission', 'reconciliation'];
  activeTab = signal('revenue');

  ytdBooked = computed(() => this.seed.accounts().reduce((s, a) => s + a.ytdRevenue, 0));
  totalBacklog = computed(() => this.seed.accounts().reduce((s, a) => s + a.backlogValue, 0));

  // Fabricated monthly booked revenue (mockup).
  private readonly months: { month: string; value: number }[] = [
    { month: 'Feb', value: 1180000 },
    { month: 'Mar', value: 1650000 },
    { month: 'Apr', value: 1420000 },
    { month: 'May', value: 1980000 },
    { month: 'Jun', value: 2240000 },
    { month: 'Jul', value: 1310000 },
  ];

  monthBars = computed<MonthBar[]>(() => {
    const max = Math.max(1, ...this.months.map((m) => m.value));
    return this.months.map((m) => ({ ...m, pct: Math.round((m.value / max) * 100) }));
  });

  accountBars = computed<AccountBar[]>(() => {
    const rows = this.seed.accounts()
      .filter((a) => a.ytdRevenue > 0)
      .map((a) => ({ name: a.name, value: a.ytdRevenue, pct: 0 }));
    const max = Math.max(1, ...rows.map((r) => r.value));
    rows.forEach((r) => (r.pct = Math.round((r.value / max) * 100)));
    return rows.sort((a, b) => b.value - a.value);
  });

  disputedCommissions = computed(() => this.seed.commissions().filter((c) => c.status === 'disputed'));

  totalDue = computed(() => this.seed.commissions().reduce((s, c) => s + c.commissionDue, 0));
  totalPaid = computed(() => this.seed.commissions().reduce((s, c) => s + c.paid, 0));

  paidPct(paid: number, due: number): number {
    if (due <= 0) return 0;
    return Math.min(100, Math.round((paid / due) * 100));
  }

  commissionBadge(status: string): string {
    switch (status) {
      case 'pending': return 'badge-warning';
      case 'reconciled': return 'badge-success';
      case 'disputed': return 'badge-danger';
      default: return 'badge-neutral';
    }
  }

  setTab(tab: string): void {
    this.router.navigate([], { queryParams: { tab }, queryParamsHandling: 'merge' });
  }

  constructor(public seed: SeedService, private route: ActivatedRoute, private router: Router) {
    const t = this.route.snapshot.queryParamMap.get('tab');
    this.activeTab.set(t && this.tabs.includes(t) ? t : 'revenue');
    this.route.queryParamMap.subscribe((q) => {
      const tab = q.get('tab');
      this.activeTab.set(tab && this.tabs.includes(tab) ? tab : 'revenue');
    });
  }
}
